import React, { useState } from "react";
import ReactMarkdown from "react-markdown";
import remarkGfm from "remark-gfm";
import { analyzeImage } from "./api";
import { ClipLoader } from "react-spinners";

function UploadImage() {
  const [file, setFile] = useState(null);
  const [report, setReport] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const [age, setAge] = useState("");
  const [sex, setSex] = useState("");

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (!selectedFile) return;

    if (!selectedFile.type.startsWith("image/")) {
      setError("Please upload an image file");
      return;
    }

    setFile(selectedFile);
    setError("");
    setReport("");
  };

  const handleUpload = async () => {
    if (!file) {
      setError("Please select an image.");
      return;
    }

    if (!age || !sex) {
      setError("Please provide age and sex");
      return;
    }

    setLoading(true);
    setError("");
    setReport("");

    try {
      const formData = new FormData();
      formData.append("file", file);
      formData.append("age", age);
      formData.append("sex", sex);

      const data = await analyzeImage(formData);

      if (data?.analysis) {
        setReport(data.analysis);
      } else {
        setError(data?.detail || "No analysis results found");
      }
    } catch (err) {
      console.error("Analysis error:", err);
      setError(err.message || "Analysis failed. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  const MarkdownRenderer = ({ content }) => (
    <ReactMarkdown
      remarkPlugins={[remarkGfm]}
      components={{
        strong({ node, children }) {
          const text = children[0];
          if (typeof text === "string") {
            const match = text.match(/(.*?)\s*\((Certainty:\s*\d+%)\)/);
            if (match) {
              return (
                <span className="font-semibold">
                  {match[1]}{" "}
                  <span className="text-blue-600 dark:text-blue-400">
                    ({match[2]})
                  </span>
                </span>
              );
            }
          }
          return <strong>{children}</strong>;
        },
        p: ({ node, children }) => (
          <p className="mb-4 leading-relaxed">{children}</p>
        ),
        ul: ({ node, children }) => (
          <ul className="list-disc pl-6 mb-4">{children}</ul>
        ),
        li: ({ node, children }) => (
          <li className="mb-2">{children}</li>
        )
      }}
    >
      {content}
    </ReactMarkdown>
  );

  return (
    <div className="p-6 bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-2xl mx-auto">
      <h2 className="text-2xl font-bold mb-6 text-gray-800 dark:text-gray-100">
        Medical Image Analysis
      </h2>

      <div className="space-y-4">
        {/* File Upload */}
        <div className="space-y-2">
          <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
            Select Image
          </label>
          <input
            type="file"
            onChange={handleFileChange}
            accept="image/*"
            className="block w-full text-sm text-gray-500
              file:mr-4 file:py-2 file:px-4
              file:rounded-lg file:border-0
              file:text-sm file:font-semibold
              file:bg-blue-600 file:text-white
              hover:file:bg-blue-700 transition-colors"
          />
        </div>

        {/* Patient Info */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
              Age
            </label>
            <input
              type="number"
              value={age}
              onChange={(e) => setAge(e.target.value.replace(/[^0-9]/g, ''))}
              min="0"
              max="120"
              className="w-full p-2 border rounded-lg dark:bg-gray-700 dark:border-gray-600"
              placeholder="Patient age"
              required
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">
              Sex
            </label>
            <select
              value={sex}
              onChange={(e) => setSex(e.target.value)}
              className="w-full p-2 border rounded-lg dark:bg-gray-700 dark:border-gray-600"
              required
            >
              <option value="">Select...</option>
              <option value="Male">Male</option>
              <option value="Female">Female</option>
              <option value="Other">Other</option>
            </select>
          </div>
        </div>

        {/* Analyze Button */}
        <button
          onClick={handleUpload}
          disabled={loading || !file}
          className={`w-full py-3 px-6 rounded-lg font-semibold text-white transition-colors
            ${loading || !file ? 'bg-gray-400 cursor-not-allowed' : 'bg-blue-600 hover:bg-blue-700'}`}
        >
          {loading ? (
            <div className="flex items-center justify-center gap-2">
              <ClipLoader color="#ffffff" size={20} />
              <span>Analyzing...</span>
            </div>
          ) : (
            'Analyze Image'
          )}
        </button>

        {/* Error Message */}
        {error && (
          <div className="p-3 bg-red-100 dark:bg-red-900 text-red-700 dark:text-red-100 rounded-lg">
            {error}
          </div>
        )}

        {/* Analysis Results */}
        {report && !error && (
          <div className="mt-6 bg-gray-50 dark:bg-gray-700 p-6 rounded-lg shadow-inner">
            <h3 className="text-xl font-semibold mb-4 text-gray-800 dark:text-gray-100">
              Analysis Report
            </h3>
            <div className="prose dark:prose-invert max-w-none">
              <MarkdownRenderer content={report} />
            </div>
            <p className="mt-4 text-sm text-gray-600 dark:text-gray-400">
              * AI-generated analysis - Must be validated by a medical professional
            </p>
          </div>
        )}
      </div>
    </div>
  );
}

export default UploadImage;
